async function run(agent) {
  await agent.aiTap("进入 Menu");
  await agent.aiTap("点击 Settings");
  await agent.aiTap("点击 Visualization");
  await agent.aiTap("启用 Show OK Code Field");
  await agent.aiTap("保存 Visualization 设置");
  await agent.aiInput("OK Code / command field", { value: "ABSOL" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiInput("Asset", { value: "_mobilephone_" });
  await agent.aiInput("Sub-number", { value: "<mobilephone>" });
  await agent.aiInput("Trans. type", { value: "1050" });
  await agent.aiTap("打开 Transaction Type 搜索帮助/下拉列表。");
  await agent.aiTap("在 Transaction Type 列表中选择匹配的 1050 交易类型。");
  await agent.aiTap("点击 OK 图标确认交易类型。");
  await agent.aiInput("Document date", { value: "29.05.2026" });
  await agent.aiInput("Asset value date", { value: "29.05.2026" });
  await agent.aiInput("Text", { value: "mobilephone" });
  await agent.aiInput("Company code", { value: "JPL1" });
  await agent.aiTap("切换到 Additional details 页签。");
  await agent.aiInput("Additional details required field", { value: "<SOP default>" });
  await agent.aiTap("点击检查/模拟或行项目按钮，进入行项目/Performance 窗口。");
  await agent.aiTap("在行项目表格中选择/确认 FIOU Center 或成本对象行。");
  await agent.aiTap("点击保存图标 sap_190 过账资产交易。");
  await agent.aiAssert("确认状态栏显示 asset transaction posted with document no.，且文本包含 mobilephone 和 company code JPL1。");
  await agent.aiTap("关闭 Performance/提示窗口。");
  await agent.aiInput("OK Code / command field", { value: "AS03" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiInput("Asset", { value: "_mobilephone_" });
  await agent.aiTap("点击 Asset values 图标/按钮。");
  const assetValueAreas = await agent.aiQuery("string, 读取 Asset Explorer 中 01 IFRS in local currency JPY 和 E10 Local GAAP in local currency 的资产值区域。");
  await agent.aiTap("返回 SAP Easy Access，重新输入 ABSOL 开始第二笔 capitalization/currency difference posting。");
  await agent.aiInput("Trans. type", { value: "<transaction type from SOP list>" });
  await agent.aiInput("Document date / Asset value date", { value: "29.05.2026" });
  await agent.aiInput("Offsetting account", { value: "<offsetting account>" });
  await agent.aiInput("Text", { value: "Capitalization currency diffr" });
  await agent.aiTap("切换到 Additional details 并补齐必填字段。");
  await agent.aiTap("保存第二笔资产交易。");
  await agent.aiInput("OK Code / command field", { value: "AS03" });
  await agent.aiInput("Company code", { value: "JPL1" });
  await agent.aiTap("打开 Asset values。");
  await agent.aiAssert("确认 Asset Explorer 可看到 01 IFRS/local currency 与 E10 Local GAAP/local currency 的资产值/币种行。");
}
